for (const template of ['plugin.client', 'plugin.server']) {
  addPlugin(resolve(runtimeDir, template))
}

try {
  window.localStorage?.setItem(storageKey, preference)
}
catch {
  // Ignore localStorage write errors; storage may be blocked.
}

const pluginOptions: BundlerPluginOptions = {
  sourcemap: !!nuxt.options.sourcemap.server || !!nuxt.options.sourcemap.client,
}

for (const child of children) {
  const childOptions = ctx.optionsResolver(child, allLocales as string[])
  if (!canCompactRoute(childOptions, allLocales)) { return false }
  if (!canCompactChildren(child.children, allLocales, ctx)) { return false }
}

addServerHandler({
  route: `${ctx.options.serverRoutePrefix}/:hash/:locale/messages.json`,
  handler: ctx.resolver.resolve('./runtime/server/routes/messages'),
})

if (!nuxt.options.experimental.typedPages || userOptions.experimental?.typedPages === false) {
  return undefined
}

nuxt.hook('prepare:types', ({ references }) => {
  // This file will be generated by type-generation plugin
  references.push({ path: declarationFile })
})

if (a.score === b.score) {
  // if scores are equal then pick more specific (longer) code.
  return b.code.length - a.code.length
}

const currentRoute = options.getLocaleRoute(
  Object.assign({}, route, { path: undefined, name: options.getRouteBaseName(route) }),
)

const matches = locales.filter(
  locale => normalizeDomain(locale.domain) === host || toArray(locale.domains).includes(host),
)

for (const detected of detect()) {
  if (detected && isSupportedLocale(detected)) {
    return detected
  }
}

if (options.components?.prose) {
  addComponentsDir({
    path: resolver.resolve('./runtime/components/prose'),
    pathPrefix: false,
    prefix: '',
    global: true,
  })
}

const result: Element = {
  type: 'element',
  tagName: 'a',
  properties,
  children: state.all(node),
}

const result: Element = {
  type: 'element',
  tagName: node.ordered ? 'ol' : 'ul',
  properties,
  children: state.wrap(results, true),
}

if (Object.keys(data).length) {
  return stringifyFrontMatter(data, result.value as string, options.frontMatter?.options)
}

if (remoteDebug && !remoteDebug.error && remoteDebug.hasRemoteDebug) {
  productionData.value = remoteDebug
  productionLoading.value = false
  return
}

if (config.robotsTxt) {
  // add robots.txt server handler
  addServerHandler({
    route: '/robots.txt',
    handler: resolve('./runtime/server/routes/robots-txt'),
  })
}

if (securityOptions.headers) {
  const globalSecurityHeaders = getHeadersApplicableToAllResources(securityOptions.headers)
  nuxt.options.nitro.routeRules = defuReplaceArray(
    { '/**' : { headers: globalSecurityHeaders } },
    nuxt.options.nitro.routeRules
  )
}

addServerHandler({
  handler: resolver.resolve('./runtime/server/middleware/allowedMethodsRestricter')
})

if (securityOptions.csrf) {
  if (Object.keys(securityOptions.csrf).length) {
    await installModule('nuxt-csurf', securityOptions.csrf)
  } else {
    await installModule('nuxt-csurf')
  }
}

nuxt.options.runtimeConfig.security = defu(
  nuxt.options.runtimeConfig.security,
  {
    ...nuxt.options.security
  }
)

if (config.zeroRuntime && !prerenderSitemap) {
  prerenderSitemap = true
  addPrerenderRoutes('/sitemap.xml')
  if (!nuxt.options.dev)
    logger.info('`zeroRuntime` enabled - sitemap routes will be prerendered.')
}

if (!config.zeroRuntime) {
  if (config.experimentalWarmUp)
    addServerPlugin(resolve('./runtime/server/plugins/warm-up'))
  if (config.experimentalCompression)
    addServerPlugin(resolve('./runtime/server/plugins/compression'))
}

const dynamicRuntimeConfig = {
  cacheMaxAgeSeconds: runtimeConfig.cacheMaxAgeSeconds,
  debug: runtimeConfig.debug,
}

for (const s of Object.keys(_sitemaps)) {
  const sitemap = _sitemaps[s]!
  // resolve the sources
  sitemaps[s] = {
    ...sitemap,
    sources: attachUrlWarnings(await resolveSitemapSources(await childSitemapSources(sitemap), e)),
  } as SitemapDefinition
}
